  1	import * as React from 'react';
  2	
  3	import {
  4	  Chart,
  5	  ChartAxis,
  6	  ChartBar,
  7	  ChartGroup,
  8	  ChartLabel,
  9	  ChartLegend,
 10	  ChartTooltip,
 11	  ChartVoronoiContainer,
 12	} from '@patternfly/react-charts';
 13	import { Card, CardTitle, EmptyState, EmptyStateBody } from '@patternfly/react-core';
 14	import { createAlertsChartBars, formatDate, generateDateArray } from '../utils';
 15	import { getResizeObserver } from '@patternfly/react-core';
 16	import { useDispatch, useSelector } from 'react-redux';
 17	import t_global_color_status_danger_default from '@patternfly/react-tokens/dist/esm/t_global_color_status_danger_default';
 18	import t_global_color_status_info_default from '@patternfly/react-tokens/dist/esm/t_global_color_status_info_default';
 19	import t_global_color_status_warning_default from '@patternfly/react-tokens/dist/esm/t_global_color_status_warning_default';
 20	import * as _ from 'lodash-es';
 21	import { setAlertsAreLoading } from '../../../actions/observe';
 22	
 23	const AlertsChart = ({ chartDays, theme }) => {
 24	  const dispatch = useDispatch();
 25	  const [chartData, setChartData] = React.useState([]);
 26	  const [chartContainerHeight, setChartContainerHeight] = React.useState();
 27	  const [chartHeight, setChartHeight] = React.useState();
 28	  const alertsData = useSelector((state) =>
 29	    state.plugins.mcp.getIn(['incidentsData', 'alertsData']),
 30	  );
 31	  const alertsAreLoading = useSelector((state) =>
 32	    state.plugins.mcp.getIn(['incidentsData', 'alertsAreLoading']),
 33	  );
 34	  const filteredData = useSelector((state) =>
 35	    state.plugins.mcp.getIn(['incidentsData', 'filteredIncidentsData']),
 36	  );
 37	  const incidentGroupId = useSelector((state) =>
 38	    state.plugins.mcp.getIn(['incidentsData', 'incidentGroupId']),
 39	  );
 40	  React.useEffect(() => {
 41	    setChartContainerHeight(chartData?.length < 5 ? 300 : chartData?.length * 60);
 42	    setChartHeight(chartData?.length < 5 ? 250 : chartData?.length * 55);
 43	  }, [chartData]);
 44	  const dateValues = generateDateArray(chartDays);
 45	
 46	  React.useEffect(() => {
 47	    setChartData(alertsData.map((alert) => createAlertsChartBars(alert, theme, dateValues)));
 48	    // eslint-disable-next-line react-hooks/exhaustive-deps
 49	  }, [alertsData]);
 50	
 51	  React.useEffect(() => {
 52	    //state when chosen incident not passing filters or the is no data
 53	    if (
 54	      _.isEmpty(filteredData) ||
 55	      !filteredData.find((incident) => incident.group_id === incidentGroupId)
 56	    ) {
 57	      dispatch(setAlertsAreLoading({ alertsAreLoading: true }));
 58	    } //state when chosen incident passing filters
 59	    else if (filteredData.find((incident) => incident.group_id === incidentGroupId)) {
 60	      dispatch(setAlertsAreLoading({ alertsAreLoading: false }));
 61	    }
 62	    // eslint-disable-next-line react-hooks/exhaustive-deps
 63	  }, [filteredData]);
 64	
 65	  const [width, setWidth] = React.useState(0);
 66	  const containerRef = React.useRef(null);
 67	  const handleResize = () => {
 68	    if (containerRef.current && containerRef.current.clientWidth) {
 69	      setWidth(containerRef.current.clientWidth);
 70	    }
 71	  };
 72	  React.useEffect(() => {
 73	    const observer = getResizeObserver(containerRef.current, handleResize);
 74	    handleResize();
 75	    return () => observer();
 76	  }, []);
 77	
 78	  return (
 79	    <Card className="alerts-chart-card">
 80	      <div ref={containerRef}>
 81	        <CardTitle>Alerts Timeline</CardTitle>
 82	        {alertsAreLoading ? (
 83	          <EmptyState
 84	            variant="large"
 85	            style={{
 86	              height: '250px',
 87	            }}
 88	          >
 89	            <EmptyStateBody>Select an incident in the chart above to see alerts.</EmptyStateBody>
 90	          </EmptyState>
 91	        ) : (
 92	          <div
 93	            style={{
 94	              height: { chartContainerHeight },
 95	              width: '100%',
 96	            }}
 97	          >
 98	            <Chart
 99	              containerComponent={
100	                <ChartVoronoiContainer
101	                  labelComponent={
102	                    <ChartTooltip constrainToVisibleArea labelComponent={<ChartLabel />} />
103	                  }
104	                  labels={({ datum }) => {
105	                    if (datum.nodata) {
106	                      return null;
107	                    }
108	                    return `Alert Severity: ${datum.severity}
109	                    Alert Name: ${datum.name ? datum.name : '---'}
110	                    Namespace: ${datum.namespace ? datum.namespace : '---'}
111	                    Layer: ${datum.layer ? datum.layer : '---'}
112	                    Component: ${datum.component}
113	                    Start: ${formatDate(new Date(datum.y0), true)}
114	                    End: ${
115	                      datum.alertstate === 'firing' ? '---' : formatDate(new Date(datum.y), true)
116	                    }`;
117	                  }}
118	                />
119	              }
120	              domainPadding={{ x: [30, 25] }}
121	              legendData={[
122	                {
123	                  name: 'Critical',
124	                  symbol: {
125	                    fill: theme === 'light' ? t_global_color_status_danger_default.var : '#C9190B',
126	                  },
127	                },
128	                {
129	                  name: 'Info',
130	                  symbol: {
131	                    fill: theme === 'light' ? t_global_color_status_info_default.var : '#06C',
132	                  },
133	                },
134	                {
135	                  name: 'Warning',
136	                  symbol: {
137	                    fill: theme === 'light' ? t_global_color_status_warning_default.var : '#F0AB00',
138	                  },
139	                },
140	              ]}
141	              legendComponent={
142	                <ChartLegend
143	                  labelComponent={
144	                    <ChartLabel style={{ fill: theme === 'light' ? '#1b1d21' : '#e0e0e0' }} />
145	                  }
146	                />
147	              }
148	              legendPosition="bottom-left"
149	              //this should be always less than the container height
150	              height={chartHeight}
151	              padding={{
152	                bottom: 75, // Adjusted to accommodate legend
153	                left: 50,
154	                right: 25, // Adjusted to accommodate tooltip
155	                top: 50,
156	              }}
157	              width={width}
158	            >
159	              <ChartAxis
160	                dependentAxis
161	                showGrid
162	                tickFormat={(t) =>
163	                  new Date(t).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
164	                }
165	                tickValues={dateValues}
166	                tickLabelComponent={
167	                  <ChartLabel style={{ fill: theme === 'light' ? '#1b1d21' : '#e0e0e0' }} />
168	                }
169	              />
170	              <ChartGroup horizontal>
171	                {chartData.map((bar, index) => {
172	                  return (
173	                    //we have several arrays and for each array we make a ChartBar
174	                    <ChartBar
175	                      data={bar}
176	                      key={index}
177	                      style={{
178	                        data: {
179	                          fill: ({ datum }) => datum.fill,
180	                          stroke: ({ datum }) => datum.fill,
181	                          fillOpacity: ({ datum }) => (datum.nodata ? 0 : 1),
182	                        },
183	                      }}
184	                    />
185	                  );
186	                })}
187	              </ChartGroup>
188	            </Chart>
189	          </div>
190	        )}
191	      </div>
192	    </Card>
193	  );
194	};
195	
196	export default AlertsChart;

