 13	import { Card, CardTitle, EmptyState, EmptyStateBody } from '@patternfly/react-core';
 14	import { createAlertsChartBars, formatDate, generateDateArray } from '../utils';
 15	import { getResizeObserver } from '@patternfly/react-core';
 16	import { useDispatch, useSelector } from 'react-redux';
 17	import t_global_color_status_danger_default from '@patternfly/react-tokens/dist/esm/t_global_color_status_danger_default';
 18	import t_global_color_status_info_default from '@patternfly/react-tokens/dist/esm/t_global_color_status_info_default';
 19	import t_global_color_status_warning_default from '@patternfly/react-tokens/dist/esm/t_global_color_status_warning_default';
 20	import * as _ from 'lodash-es';
 21	import { setAlertsAreLoading } from '../../../actions/observe';
 22	
 23	const AlertsChart = ({ chartDays, theme }) => {
 24	  const dispatch = useDispatch();
 25	  const [chartData, setChartData] = React.useState([]);
 26	  const [chartContainerHeight, setChartContainerHeight] = React.useState();
 27	  const [chartHeight, setChartHeight] = React.useState();
 28	  const alertsData = useSelector((state) =>
 29	    state.plugins.mcp.getIn(['incidentsData', 'alertsData']),
 30	  );
 31	  const alertsAreLoading = useSelector((state) =>
 32	    state.plugins.mcp.getIn(['incidentsData', 'alertsAreLoading']),
 33	  );
 34	  const filteredData = useSelector((state) =>
 35	    state.plugins.mcp.getIn(['incidentsData', 'filteredIncidentsData']),
 36	  );
 37	  const incidentGroupId = useSelector((state) =>
 38	    state.plugins.mcp.getIn(['incidentsData', 'incidentGroupId']),
 39	  );
 40	  React.useEffect(() => {
 41	    setChartContainerHeight(chartData?.length < 5 ? 300 : chartData?.length * 60);
 42	    setChartHeight(chartData?.length < 5 ? 250 : chartData?.length * 55);
 43	  }, [chartData]);
 44	  const dateValues = generateDateArray(chartDays);
 45	
 46	  React.useEffect(() => {
 47	    setChartData(alertsData.map((alert) => createAlertsChartBars(alert, theme, dateValues)));
 48	    // eslint-disable-next-line react-hooks/exhaustive-deps
 49	  }, [alertsData]);
 50	
 51	  React.useEffect(() => {
 52	    //state when chosen incident not passing filters or the is no data
 53	    if (
 54	      _.isEmpty(filteredData) ||
 55	      !filteredData.find((incident) => incident.group_id === incidentGroupId)
 56	    ) {
 57	      dispatch(setAlertsAreLoading({ alertsAreLoading: true }));
 58	    } //state when chosen incident passing filters
 59	    else if (filteredData.find((incident) => incident.group_id === incidentGroupId)) {
 60	      dispatch(setAlertsAreLoading({ alertsAreLoading: false }));
 61	    }
 62	    // eslint-disable-next-line react-hooks/exhaustive-deps
 63	  }, [filteredData]);
 64	
 65	  const [width, setWidth] = React.useState(0);
 66	  const containerRef = React.useRef(null);
 67	  const handleResize = () => {
 68	    if (containerRef.current && containerRef.current.clientWidth) {
 69	      setWidth(containerRef.current.clientWidth);
 70	    }
 71	  };
 72	  React.useEffect(() => {
 73	    const observer = getResizeObserver(containerRef.current, handleResize);
 74	    handleResize();
 75	    return () => observer();
 76	  }, []);
 77	
 78	  return (
 79	    <Card className="alerts-chart-card">
 80	      <CardTitle>Alerts Timeline</CardTitle>
 81	      <div ref={containerRef}>
 82	        {alertsAreLoading ? (
 83	          <EmptyState
 84	            titleText="No Alerts"
 85	            variant="large"
 86	            style={{
 87	              height: '250px',
 88	            }}
 89	          >
 90	            <EmptyStateBody>Select an incident in the chart above to see alerts.</EmptyStateBody>
 91	          </EmptyState>
 92	        ) : (
 93	          <div
 94	            style={{
 95	              height: { chartContainerHeight },
 96	              width: '100%',
 97	            }}
 98	          >
 99	            <Chart
100	              containerComponent={
101	                <ChartVoronoiContainer
102	                  labelComponent={
103	                    <ChartTooltip constrainToVisibleArea labelComponent={<ChartLabel />} />
104	                  }
105	                  labels={({ datum }) => {
106	                    if (datum.nodata) {
107	                      return null;
108	                    }
109	                    return `Alert Severity: ${datum.severity}
110	                    Alert Name: ${datum.name ? datum.name : '---'}
111	                    Namespace: ${datum.namespace ? datum.namespace : '---'}
112	                    Layer: ${datum.layer ? datum.layer : '---'}
113	                    Component: ${datum.component}
114	                    Start: ${formatDate(new Date(datum.y0), true)}
115	                    End: ${
116	                      datum.alertstate === 'firing' ? '---' : formatDate(new Date(datum.y), true)
117	                    }`;
118	                  }}
119	                />
120	              }
121	              domainPadding={{ x: [30, 25] }}
122	              legendData={[
123	                {
124	                  name: 'Critical',
125	                  symbol: {
126	                    fill: theme === 'light' ? t_global_color_status_danger_default.var : '#C9190B',
127	                  },
128	                },
129	                {
130	                  name: 'Info',
131	                  symbol: {
132	                    fill: theme === 'light' ? t_global_color_status_info_default.var : '#06C',
133	                  },
134	                },
135	                {
136	                  name: 'Warning',
137	                  symbol: {
138	                    fill: theme === 'light' ? t_global_color_status_warning_default.var : '#F0AB00',
139	                  },
140	                },
141	              ]}
142	              legendComponent={
143	                <ChartLegend
144	                  labelComponent={
145	                    <ChartLabel style={{ fill: theme === 'light' ? '#1b1d21' : '#e0e0e0' }} />
146	                  }
147	                />
148	              }
149	              legendPosition="bottom-left"
150	              //this should be always less than the container height
151	              height={chartHeight}
152	              padding={{
153	                bottom: 75, // Adjusted to accommodate legend
154	                left: 50,
155	                right: 25, // Adjusted to accommodate tooltip
156	                top: 50,
157	              }}
158	              width={width}
159	            >
160	              <ChartAxis
161	                dependentAxis
162	                showGrid
163	                tickFormat={(t) =>
164	                  new Date(t).toLocaleDateString('en-US', { month: 'short', day: 'numeric' })
165	                }
166	                tickValues={dateValues}
167	                tickLabelComponent={
168	                  <ChartLabel style={{ fill: theme === 'light' ? '#1b1d21' : '#e0e0e0' }} />
169	                }
170	              />
171	              <ChartGroup horizontal>
172	                {chartData.map((bar, index) => {
173	                  return (
174	                    //we have several arrays and for each array we make a ChartBar
175	                    <ChartBar
176	                      data={bar}
177	                      key={index}
178	                      style={{
179	                        data: {
180	                          fill: ({ datum }) => datum.fill,
181	                          stroke: ({ datum }) => datum.fill,
182	                          fillOpacity: ({ datum }) => (datum.nodata ? 0 : 1),
183	                        },
184	                      }}
185	                    />
186	                  );
187	                })}
188	              </ChartGroup>
189	            </Chart>
190	          </div>
191	        )}
192	      </div>
193	    </Card>
194	  );
195	};
